changeSet.sql:
-- hive_index_pattern: '_v3_hive_alert-*' → 'v3-hive-alert-*' UPDATE hive_index_pattern SET pattern = REPLACE(pattern, '_v3_hive_', 'v3-hive-') WHERE pattern LIKE '_v3\_hive\_%' ESCAPE '\';
-- hive_menu: '&indexPattern=_v3_hive_log-*' → '&indexPattern=v3-hive-log-*' UPDATE hive_menu SET url = REPLACE(url, '&indexPattern=_v3_hive_', '&indexPattern=v3-hive-') WHERE url LIKE '%&indexPattern=_v3\_hive\_%' ESCAPE '\';
-- hive_correlation_rules: rule_after_events_def JSON UPDATE hive_correlation_rules SET rule_after_events_def = REPLACE(rule_after_events_def, '"indexPattern":"_v3_hive_', '"indexPattern":"v3-hive-') WHERE rule_after_events_def LIKE '%"indexPattern":"_v3\_hive\_%' ESCAPE '\';
-- hive_dashboard: filters JSON UPDATE hive_dashboard SET filters = REPLACE(filters, '"indexPattern":"_v3_hive_', '"indexPattern":"v3-hive-') WHERE filters LIKE '%"indexPattern":"_v3\_hive\_%' ESCAPE '\';
